### Which @angular/* package(s) are the source of the bug?

core

### Is this a regression?

Yes

### Description

I wanted to use the new DestroyRef instead of ngOnDestroy. But the onDestroy removes the value and destroyRef does not.

Abstract class:
```ts
@Directive()
export abstract class InputDirective<T> {

  label = input.required<string>();
  key = input.required<string>();
  value = model.required<T | undefined | null>();

  destroyRef = inject(DestroyRef);

  ngOnDestroy() {
    console.log('ngOnDestroy', this.value())
  }

  constructor() {
    this.destroyRef.onDestroy(() => {
      console.warn(' destroyRef', this.value())
    })

    effect(() => {
      console.log(this.value())
    })


    // update the value live when typing
    let valueChangesSubscription: Subscription | null = null;

    effect(() => {
      this.formControl.setValue(this.value());

      if (valueChangesSubscription === null) {
        valueChangesSubscription = this.formControl.valueChanges
          .pipe(takeUntilDestroyed(this.destroyRef))
          .subscribe((value) => {
            if (this.value() !== value) {
              this.value.set(value);
            }
          });
      }
    });
  }

}

```

Example of a `input.component.ts`:
```ts
@Component({
  selector: 'lib-number-input',
})
export class NumberInputComponent extends InputDirective<number | string> {
  constructor() {
    super();
  }
}
```

Using the component in another html file
```html
        <lib-number-input label="Costruzione Manufatti, Up to 300 dm3"
                          [(value)]="form.construzioneManufatti"
                          key="construzioneManufatti"
        />
```


But when you do it this order it looks like it is correct.
